import { type PropsWithChildren } from 'react';

import { CategoricalBarChartCategoryAxisContext } from '../contexts/CategoricalBarChartCategoryAxis.context.js';
import { CategoricalBarChartLegendContext } from '../contexts/CategoricalBarChartLegend.context.js';
import { CategoricalBarChartThresholdsContext } from '../contexts/CategoricalBarChartThresholds.context.js';
import { CategoricalBarChartTooltipContext } from '../contexts/CategoricalBarChartTooltip.context.js';
import { CategoricalBarChartTruncationModeContext } from '../contexts/CategoricalBarChartTruncationMode.context.js';
import { CategoricalBarChartValueAxisContext } from '../contexts/CategoricalBarChartValueAxis.context.js';
import { RequiredCategoricalBarChartConfiguration } from '../types/categorical-bar-chart.js';

interface CategoricalBarChartProvidersProps {
  config: RequiredCategoricalBarChartConfiguration;
}

export const CategoricalBarChartProviders = (
  props: PropsWithChildren<CategoricalBarChartProvidersProps>,
) => {
  const { config, children } = props;

  return (
    <CategoricalBarChartTooltipContext.Provider value={config.tooltip}>
      <CategoricalBarChartValueAxisContext.Provider value={config.valueAxis}>
        <CategoricalBarChartCategoryAxisContext.Provider
          value={config.categoryAxis}
        >
          <CategoricalBarChartThresholdsContext.Provider
            value={config.thresholdIndicators}
          >
            <CategoricalBarChartTruncationModeContext.Provider
              value={config.truncationMode}
            >
              <CategoricalBarChartLegendContext.Provider value={config.legend}>
                {children}
              </CategoricalBarChartLegendContext.Provider>
            </CategoricalBarChartTruncationModeContext.Provider>
          </CategoricalBarChartThresholdsContext.Provider>
        </CategoricalBarChartCategoryAxisContext.Provider>
      </CategoricalBarChartValueAxisContext.Provider>
    </CategoricalBarChartTooltipContext.Provider>
  );
};
